    "extract": "",
    "patchFile": "Sts-120-patch.svg",
    "image": "https://upload.wikimedia.org/wikipedia/commons/thumb/b/bf/Sts-120-patch.svg/960px-Sts-120-patch.svg.png",
    "originalImage": "https://upload.wikimedia.org/wikipedia/commons/b/bf/Sts-120-patch.svg",
